// Show more / Hide
document.querySelectorAll(".info_cart-item_btn").forEach(function(btn) {
    btn.addEventListener("click", function() {
        var card = btn.closest(".info_cart-item");
        var isOpen = card.classList.toggle("open");
        btn.textContent = isOpen ? "Hide" : "Show more";
    });
});

// Бургер меню
var burger = document.querySelector(".navbar_burger");
var navMenu = document.querySelector(".navbar_menu");
if (burger && navMenu) {
    burger.addEventListener("click", function() {
        burger.classList.toggle("active");
        navMenu.classList.toggle("open");
    });
    navMenu.querySelectorAll("a").forEach(function(link) {
        link.addEventListener("click", function() {
            burger.classList.remove("active");
            navMenu.classList.remove("open");
        });
    });
}

// Модальные окна
function openModal(id) {
    var modal = document.getElementById(id);
    if (modal) { modal.classList.add("open"); document.body.style.overflow = "hidden"; }
}
function closeModal(modal) {
    modal.classList.remove("open");
    document.body.style.overflow = "";
}

document.querySelectorAll("[data-modal]").forEach(function(link) {
    link.addEventListener("click", function(e) {
        e.preventDefault();
        openModal(link.getAttribute("data-modal"));
    });
});

document.querySelectorAll(".modal_close").forEach(function(btn) {
    btn.addEventListener("click", function() { closeModal(btn.closest(".modal")); });
});

document.querySelectorAll(".modal_overlay").forEach(function(overlay) {
    overlay.addEventListener("click", function() { closeModal(overlay.closest(".modal")); });
});

document.addEventListener("keydown", function(e) {
    if (e.key === "Escape") {
        document.querySelectorAll(".modal.open").forEach(function(modal) { closeModal(modal); });
    }
});
